?><!DOCTYPE html><html><head><title>Expiry Alerts</title><link rel="stylesheet" href="assets/style.css"></head><body><div class="layout"><?php include "includes/sidebar.php"; ?><main class="main"><div class="page-title"><h1>Expiry Alerts</h1><p>Forecast-based expiry warnings for FreshGuard Supermarket</p></div><div class="grid grid-3"><div class="card stat high"><h3>High Risk</h3><strong><?= $h ?></strong></div><div class="card stat medium"><h3>Medium Risk</h3><strong><?= $m ?></strong></div><div class="card stat low"><h3>Low Risk</h3><strong><?= $l ?></strong></div></div><br><?php foreach($items as $p){ if($p["risk"]!="Low"){ ?><div class="card alert-card"><h3><?= $p["product_name"] ?> <span class="badge <?= strtolower($p["risk"]) ?>"><?= $p["risk"] ?> Risk</span></h3><p><?= $p["location"] ?> • <?= $p["supplier"] ?></p><br><div class="grid grid-4"><div><strong>Stock</strong><br><?= $p["current_stock"] ?> units</div><div><strong>Forecast</strong><br><?= $p["forecast"] ?> units</div><div><strong>Suggested Discount</strong><br><?= $p["discount"] ?>%</div><div><strong>Action</strong><br><?= aiAction($p["risk"],$p["discount"]) ?></div></div></div><?php }} ?></main></div></body></html>